MERGE INTO CONSULTAS FIN USING (SELECT '002389SUBCHEQUE' INFORME ,TO_CLOB(q'[SELECT  REPLACE(REPLACE(REPLACE(REPLACE(
                V_DETALLE_AUXILIAR_CNT.FORMATO
               ,'VALOR',V_DETALLE_AUXILIAR_CNT.VLRAGIRAR)
               ,'BENEFICIARIO', V_DETALLE_AUXILIAR_CNT.TERCERO_COM_NOM) 
               ,'MONTOCOMPLETO', PCK_SYSMAN_UTL.FC_VALOR_LETRAS(V_DETALLE_AUXILIAR_CNT.VLRAGIRAR))
               ,'FECHALARGA', replace(to_char(V_DETALLE_AUXILIAR_CNT.FECHA,'DAY,dd / MONTH / yyyy'),'/','de')
              )AS CHEQUES, V_DETALLE_AUXILIAR_CNT.CODIGO_CUENTA  FROM V_DETALLE_AUXILIAR_CNT
 WHERE V_DETALLE_AUXILIAR_CNT.COMPANIA       = $P{PR_COMPANIA} 
    AND V_DETALLE_AUXILIAR_CNT.ANO          = $P{PR_ANO} 
    AND V_DETALLE_AUXILIAR_CNT.TIPO_CPTE    = $P{PR_TIPO} 
  AND V_DETALLE_AUXILIAR_CNT.COMPROBANTE = $P{PR_COMPROBANTE} 
  AND V_DETALLE_AUXILIAR_CNT.CLASECUENTA='B']') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'MROSERO' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);
  
  MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002348EGRALC_CASTILLA' INFORME_PADRE, '002389SUBCHEQUE' INFORME_HIJO, 'PR_STRSQL_INFORMESUBCHEQUE' PARAMETRO ,'MROSERO' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);